<?php
namespace App\Models\Inventory; use Illuminate\Database\Eloquent\{Factories\HasFactory,Model}; use Illuminate\Database\Eloquent\Relations\BelongsTo;
class InventoryTransaction extends Model{use HasFactory; protected $guarded=[]; protected function casts():array{return ['transaction_date'=>'date','posted_at'=>'datetime'];} public function item():BelongsTo{return $this->belongsTo(InventoryItem::class,'inventory_item_id');} public function fromLocation():BelongsTo{return $this->belongsTo(InventoryLocation::class,'from_location_id');} public function toLocation():BelongsTo{return $this->belongsTo(InventoryLocation::class,'to_location_id');} public function fromCondition():BelongsTo{return $this->belongsTo(InventoryCondition::class,'from_condition_id');} public function toCondition():BelongsTo{return $this->belongsTo(InventoryCondition::class,'to_condition_id');}}
